def bags {V : Type} [DecidableEq V] (T : State V) : Finset (Finset V) :=
  Sigma.fst T

/-- The black adjacency relation of a trigraph state. -/

def redAdj {V : Type} [DecidableEq V] (T : State V) :
    Finset V → Finset V → Prop :=
  Sigma.fst (Sigma.snd (Sigma.snd T))

def state {V : Type} [Fintype V] [DecidableEq V] {G : SimpleGraph V}
    (I : InitialState G) : State V :=
  Sigma.fst I

def FinalState (V : Type) [DecidableEq V] : Type :=
  Σ state : State V, PLift ((bags state).card ≤ 1)

/-- The underlying trigraph state of a final state. -/

noncomputable def matrixMixedNumber {n m : ℕ}
    (M : _root_.Matrix (Fin n) (Fin m) α) : ℕ :=
  sSup { k : ℕ | k ≤ min n m ∧ MixedMinor.HasMixedMinor M k }

noncomputable def orderedAdjacencyMixedNumber {V : Type*} {n : ℕ}
    (G : SimpleGraph V) [DecidableRel G.Adj] (σ : VertexOrder.Order V n) : ℕ :=
  MixedNumber.matrixMixedNumber (OrderedAdjacency.orderedAdjacency G σ)

def GraphParam :=
  ∀ {V : Type}, [Fintype V] → [DecidableEq V] →
    (G : SimpleGraph V) → [DecidableRel G.Adj] → ℕ
